import{_ as i,c as s,o as a,ae as n}from"./chunks/framework.DYDfWl-y.js";const k=JSON.parse('{"title":"Releasing","description":"","frontmatter":{},"headers":[],"relativePath":"releasing.md","filePath":"releasing.md"}'),t={name:"releasing.md"};function l(r,e,o,d,h,c){return a(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="releasing" tabindex="-1">Releasing <a class="header-anchor" href="#releasing" aria-label="Permalink to &quot;Releasing&quot;">​</a></h1><p>Dieser Leitfaden beschreibt, wie ein Release von <code>@npm9912/v-map</code> veröffentlicht wird, welche Voraussetzungen erfüllt sein müssen und welche Stolperfallen es gibt.</p><h2 id="uberblick" tabindex="-1">Überblick <a class="header-anchor" href="#uberblick" aria-label="Permalink to &quot;Überblick&quot;">​</a></h2><p>Releases laufen vollautomatisch über <a href="https://semantic-release.gitbook.io/" target="_blank" rel="noreferrer">semantic-release</a>, ausgelöst durch jeden Push auf den <code>main</code>-Branch. semantic-release liest die Conventional-Commit-Historie seit dem letzten Tag, berechnet daraus die nächste Versionsnummer und führt anschließend folgende Schritte aus:</p><ol><li>Version in <code>package.json</code> hochsetzen</li><li><code>CHANGELOG.md</code> aktualisieren</li><li>Auf npm publishen (<code>@npm9912/v-map</code>, public)</li><li>GitHub-Release mit Release Notes erstellen</li><li>Git-Tag <code>v&lt;version&gt;</code> setzen</li><li>Aktualisierte <code>package.json</code> und <code>CHANGELOG.md</code> zurück nach <code>main</code> committen (<code>chore(release): &lt;version&gt; [skip ci]</code>)</li></ol><p>Alle Plugins sind in <code>.releaserc.json</code> konfiguriert. <strong><code>.releaserc.json</code> ist die einzige Quelle der Wahrheit</strong> — semantic-release ignoriert ein parallel vorhandenes <code>release</code>-Feld in <code>package.json</code> nicht, aber doppelte Konfiguration verwirrt nur. Nicht beides pflegen.</p><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><h3 id="einmalig-repo-setup" tabindex="-1">Einmalig (Repo-Setup) <a class="header-anchor" href="#einmalig-repo-setup" aria-label="Permalink to &quot;Einmalig (Repo-Setup)&quot;">​</a></h3><ul><li><strong><code>NPM_TOKEN</code></strong> als GitHub-Actions-Secret im Repository hinterlegt. Es muss ein Token sein, der Publish-Rechte für den Scope <code>@npm9912</code> hat (Automation-Token oder Granular Token mit <code>Read and write</code> für Packages). Read-only Token funktioniert nicht.</li><li><strong><code>GITHUB_TOKEN</code></strong> ist automatisch verfügbar — nichts zu tun.</li><li><strong>Branch-Konfiguration:</strong> semantic-release published nur von <code>main</code> (<code>branches: [&quot;main&quot;]</code> in <code>.releaserc.json</code>). Andere Branches lösen kein Release aus.</li></ul><h3 id="vor-jedem-release" tabindex="-1">Vor jedem Release <a class="header-anchor" href="#vor-jedem-release" aria-label="Permalink to &quot;Vor jedem Release&quot;">​</a></h3><ul><li><code>develop</code> ist aktuell, alle CI-Jobs (Test, Test Browser, Build, Docs) sind grün.</li><li>Alle relevanten Commits folgen <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a>: <ul><li><code>feat:</code> → Minor-Bump (<code>0.1.0</code> → <code>0.2.0</code>)</li><li><code>fix:</code> → Patch-Bump (<code>0.1.0</code> → <code>0.1.1</code>)</li><li><code>BREAKING CHANGE:</code> Footer oder <code>feat!:</code> → Major-Bump (<code>0.1.0</code> → <code>1.0.0</code>)</li><li><code>chore:</code>, <code>docs:</code>, <code>test:</code>, <code>refactor:</code>, <code>style:</code>, <code>ci:</code> → kein Release</li></ul></li><li>Wenn ausschließlich Commit-Typen ohne Release-Auswirkung vorliegen, gibt semantic-release <em>kein</em> Release aus und der Workflow läuft trotzdem grün durch — das ist kein Fehler.</li></ul><h2 id="branch-strategie" tabindex="-1">Branch-Strategie <a class="header-anchor" href="#branch-strategie" aria-label="Permalink to &quot;Branch-Strategie&quot;">​</a></h2><ul><li><strong><code>develop</code></strong> ist der Integrations-Branch. Alle Feature- und Fix-Commits landen hier.</li><li><strong><code>main</code></strong> ist der Release-Branch. Auf <code>main</code> wird <strong>nicht direkt entwickelt</strong>.</li><li>Ein Release entsteht durch einen Merge <code>develop</code> → <code>main</code>.</li></ul><h2 id="release-durchfuhren" tabindex="-1">Release durchführen <a class="header-anchor" href="#release-durchfuhren" aria-label="Permalink to &quot;Release durchführen&quot;">​</a></h2><h3 id="_1-sicherstellen-dass-develop-release-fertig-ist" tabindex="-1">1. Sicherstellen, dass <code>develop</code> release-fertig ist <a class="header-anchor" href="#_1-sicherstellen-dass-develop-release-fertig-ist" aria-label="Permalink to &quot;1. Sicherstellen, dass `develop` release-fertig ist&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> develop</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ff-only</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> develop</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --branch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> develop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --limit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # alle grün?</span></span></code></pre></div><h3 id="_2-develop-nach-main-mergen" tabindex="-1">2. <code>develop</code> nach <code>main</code> mergen <a class="header-anchor" href="#_2-develop-nach-main-mergen" aria-label="Permalink to &quot;2. `develop` nach `main` mergen&quot;">​</a></h3><p><strong>Wichtig:</strong> Immer <code>--no-ff</code> (Merge-Commit), niemals Squash. semantic-release braucht die einzelnen Conventional-Commit-Messages, um die Release Notes korrekt zu generieren. Ein Squash würde alles zu einem einzigen Commit zusammenziehen und damit die gesamte Historie für die Versionsberechnung kollabieren.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ff-only</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-ff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> develop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;chore: merge develop for release&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><p>Der Push triggert automatisch den <code>Release</code>-Workflow (<code>.github/workflows/release.yml</code>).</p><h3 id="_3-release-workflow-beobachten" tabindex="-1">3. Release-Workflow beobachten <a class="header-anchor" href="#_3-release-workflow-beobachten" aria-label="Permalink to &quot;3. Release-Workflow beobachten&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --branch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --limit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">run-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --exit-status</span></span></code></pre></div><p>Was im Erfolgsfall passiert:</p><ul><li>Neuer Tag <code>v&lt;version&gt;</code> auf GitHub</li><li>Neuer Eintrag unter <a href="https://github.com/pt9912/v-map/releases" target="_blank" rel="noreferrer">Releases</a></li><li><code>pnpm view @npm9912/v-map version</code> zeigt die neue Version</li><li>Auf <code>main</code> liegt ein neuer Commit <code>chore(release): &lt;version&gt; [skip ci]</code> mit hochgesetzter <code>package.json</code> und aktualisierter <code>CHANGELOG.md</code></li></ul><h3 id="_4-main-zuruck-nach-develop-mergen" tabindex="-1">4. <code>main</code> zurück nach <code>develop</code> mergen <a class="header-anchor" href="#_4-main-zuruck-nach-develop-mergen" aria-label="Permalink to &quot;4. `main` zurück nach `develop` mergen&quot;">​</a></h3><p>Sehr wichtig und leicht zu vergessen: Der Release-Commit von semantic-release liegt ausschließlich auf <code>main</code>. Wenn er nicht zurück nach <code>develop</code> gemergt wird, divergieren Versionsnummer und <code>CHANGELOG.md</code> zwischen den Branches und beim nächsten Release-Merge gibt es Konflikte.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> develop</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ff-only</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> develop</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin/main</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # idealerweise fast-forward</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> develop</span></span></code></pre></div><h2 id="versionierung" tabindex="-1">Versionierung <a class="header-anchor" href="#versionierung" aria-label="Permalink to &quot;Versionierung&quot;">​</a></h2><ul><li>Aktueller Versionsstand: siehe <code>package.json</code> und <code>CHANGELOG.md</code>.</li><li>Das Projekt startete bewusst bei <code>0.1.0</code> (nicht <code>1.0.0</code>), um zu signalisieren, dass die API noch nicht stabilisiert ist. Realisiert über einen Placeholder-Tag <code>v0.0.0</code> auf dem Initial Commit als Baseline für semantic-release.</li><li>Solange wir auf <code>0.x</code> sind, behandeln wir auch <code>feat:</code>-Commits als potenziell brechend in Bezug auf Konsumenten — eine echte Stabilitätsgarantie kommt erst mit <code>1.0.0</code>.</li></ul><h2 id="erstes-release-einer-neuen-major-version" tabindex="-1">Erstes Release einer neuen Major-Version <a class="header-anchor" href="#erstes-release-einer-neuen-major-version" aria-label="Permalink to &quot;Erstes Release einer neuen Major-Version&quot;">​</a></h2><p>Sobald die API stabil ist und wir auf <code>1.0.0</code> gehen wollen, reicht ein einzelner Commit mit <code>BREAKING CHANGE:</code> Footer:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat: stabilize public API</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>BREAKING CHANGE: API is now considered stable. No code changes,</span></span>\n<span class="line"><span>this commit only marks the 1.0 milestone.</span></span></code></pre></div><p>semantic-release berechnet daraus den Sprung von der aktuellen <code>0.x.y</code> auf <code>1.0.0</code>.</p><h2 id="fehlerbehebung" tabindex="-1">Fehlerbehebung <a class="header-anchor" href="#fehlerbehebung" aria-label="Permalink to &quot;Fehlerbehebung&quot;">​</a></h2><h3 id="workflow-lauft-aber-kein-release-wird-erzeugt" tabindex="-1">Workflow läuft, aber kein Release wird erzeugt <a class="header-anchor" href="#workflow-lauft-aber-kein-release-wird-erzeugt" aria-label="Permalink to &quot;Workflow läuft, aber kein Release wird erzeugt&quot;">​</a></h3><p>Das ist meistens <em>kein</em> Fehler, sondern bedeutet: Es gab seit dem letzten Tag keine release-relevanten Commits (nur <code>chore:</code>, <code>docs:</code>, <code>test:</code> etc.). Im Job-Log steht dann <code>There are no relevant changes, so no new version is released.</code>.</p><h3 id="npm-publish-schlagt-mit-403-forbidden-fehl" tabindex="-1"><code>npm publish</code> schlägt mit <code>403 Forbidden</code> fehl <a class="header-anchor" href="#npm-publish-schlagt-mit-403-forbidden-fehl" aria-label="Permalink to &quot;`npm publish` schlägt mit `403 Forbidden` fehl&quot;">​</a></h3><ul><li><code>NPM_TOKEN</code> fehlt oder ist read-only.</li><li>Token gehört zu einem User ohne Publish-Rechte für den Scope <code>@npm9912</code>.</li><li>Token ist abgelaufen.</li></ul><p>Lösung: Neuen Automation-Token auf npmjs.com erstellen und in den Repo-Secrets ersetzen. Anschließend Workflow neu auslösen (<code>gh run rerun &lt;run-id&gt;</code>).</p><h3 id="semantic-release-git-kann-den-release-commit-nicht-pushen" tabindex="-1"><code>semantic-release/git</code> kann den Release-Commit nicht pushen <a class="header-anchor" href="#semantic-release-git-kann-den-release-commit-nicht-pushen" aria-label="Permalink to &quot;`semantic-release/git` kann den Release-Commit nicht pushen&quot;">​</a></h3><p>Tritt z. B. auf, wenn <code>main</code> durch Branch-Protection-Rules vor direkten Pushes geschützt ist. Workarounds:</p><ul><li>Branch Protection für <code>main</code> so konfigurieren, dass GitHub Actions pushen darf (Bypass für den Workflow-Bot).</li><li>Alternativ: <code>@semantic-release/git</code> aus den Plugins entfernen und CHANGELOG/Version manuell pflegen — wird ausdrücklich nicht empfohlen.</li></ul><h3 id="zwei-releases-hintereinander-der-zweite-schlagt-fehl" tabindex="-1">Zwei Releases hintereinander, der zweite schlägt fehl <a class="header-anchor" href="#zwei-releases-hintereinander-der-zweite-schlagt-fehl" aria-label="Permalink to &quot;Zwei Releases hintereinander, der zweite schlägt fehl&quot;">​</a></h3><p>Mögliche Ursache: <code>develop</code> wurde nach dem ersten Release nicht mit <code>main</code> synchronisiert (siehe Schritt 4 oben). Beim nächsten Merge <code>develop</code> → <code>main</code> entsteht dann ein Konflikt in <code>package.json</code> (Version) oder <code>CHANGELOG.md</code>. Lösung: erst Schritt 4 nachholen, dann den neuen Release-Merge fahren.</p><h2 id="was-niemals-tun" tabindex="-1">Was niemals tun <a class="header-anchor" href="#was-niemals-tun" aria-label="Permalink to &quot;Was niemals tun&quot;">​</a></h2><ul><li><strong>Nicht</strong> <code>[skip ci]</code> aus dem <code>chore(release):</code> Commit-Message-Template entfernen. Sonst löst der Release-Commit selbst wieder den Release-Workflow aus → Endlosschleife.</li><li><strong>Nicht</strong> Tags von Hand erstellen oder löschen, die zum semantic-release-Schema passen (<code>v&lt;x&gt;.&lt;y&gt;.&lt;z&gt;</code>). semantic-release nutzt sie als Versionsbaseline und gerät sonst durcheinander.</li><li><strong>Nicht</strong> mit <code>--force</code> auf <code>main</code> pushen. Ein einmal veröffentlichter Commit hängt an einem npm-Release und einem GitHub-Release; die zu überschreiben hinterlässt inkonsistenten Zustand.</li><li><strong>Nicht</strong> <code>develop</code> direkt nach npm publishen. Nur <code>main</code> ist als Release-Branch konfiguriert.</li></ul>',46)])])}const u=i(t,[["render",l]]);export{k as __pageData,u as default};
